(function () {
  'use strict';

  // ---- Constants (generated by encrypt.mjs --init) ----
  const SALT_HEX = '15f1ae5a6c02386a8e75a1643b0e5248';
  const VERIFIER = 'e8818adc2fd6767b32b4b27bdf623a45f304d5d88f441e6f8cd4884cb362ec1a';

  const PBKDF2_ITERATIONS = 100000;

  // ---- Helpers ----

  function hexToBytes(hex) {
    const bytes = new Uint8Array(hex.length / 2);
    for (let i = 0; i < bytes.length; i++) {
      bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
    }
    return bytes;
  }

  function bytesToHex(bytes) {
    return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
  }

  function b64ToBytes(b64) {
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    return bytes;
  }

  // ---- Core crypto ----

  async function deriveRawKey(password) {
    const enc = new TextEncoder();
    const keyMaterial = await crypto.subtle.importKey(
      'raw', enc.encode(password), 'PBKDF2', false, ['deriveBits']
    );
    const bits = await crypto.subtle.deriveBits(
      { name: 'PBKDF2', salt: hexToBytes(SALT_HEX), iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
      keyMaterial, 256
    );
    return new Uint8Array(bits);
  }

  async function deriveAesKey(rawKey) {
    return crypto.subtle.importKey('raw', rawKey, { name: 'AES-GCM' }, false, ['decrypt']);
  }

  async function sha256Hex(data) {
    const hash = await crypto.subtle.digest('SHA-256', data);
    return bytesToHex(new Uint8Array(hash));
  }

  // ---- Public API ----

  async function verify(password) {
    const rawKey = await deriveRawKey(password);
    const hash = await sha256Hex(rawKey);
    return hash === VERIFIER;
  }

  async function deriveKeyHex(password) {
    const rawKey = await deriveRawKey(password);
    return bytesToHex(rawKey);
  }

  async function decrypt(password, encryptedB64, ivB64) {
    const rawKey = await deriveRawKey(password);
    const aesKey = await deriveAesKey(rawKey);
    const plainBuf = await crypto.subtle.decrypt(
      { name: 'AES-GCM', iv: b64ToBytes(ivB64) },
      aesKey, b64ToBytes(encryptedB64)
    );
    return new TextDecoder().decode(plainBuf);
  }

  async function decryptWithKey(hexKey, encryptedB64, ivB64) {
    const rawKey = hexToBytes(hexKey);
    const aesKey = await deriveAesKey(rawKey);
    const plainBuf = await crypto.subtle.decrypt(
      { name: 'AES-GCM', iv: b64ToBytes(ivB64) },
      aesKey, b64ToBytes(encryptedB64)
    );
    return new TextDecoder().decode(plainBuf);
  }

  // ---- Expose ----

  window.LettersAuth = {
    verify: verify,
    deriveKeyHex: deriveKeyHex,
    decrypt: decrypt,
    decryptWithKey: decryptWithKey,
    SALT_HEX: SALT_HEX,
    VERIFIER: VERIFIER
  };
})();
